<x-form.checkbox name="payments_enabled" label="پرداخت آنلاین فعال باشد" :checked="$paymentsEnabled" wrapper-class="flex items-center justify-between gap-3 rounded-xl border border-slate-200 bg-slate-50 p-4 text-sm font-bold" />
<x-form.select name="default_payment_gateway" label="درگاه پیش‌فرض" :selected="$defaultPaymentGateway" :options="$paymentGateways" />
