<div class="rounded-xl border border-slate-200 bg-slate-50 p-4"><h2 class="font-black">حسابرو</h2><div class="mt-4 grid gap-4 md:grid-cols-2"><x-form.checkbox name="hesabro_payment_enabled" label="درگاه حسابرو فعال باشد" :checked="$hesabroPaymentEnabled" wrapper-class="flex items-center justify-between gap-3 rounded-lg border border-slate-200 bg-white p-3 text-sm font-bold md:col-span-2" /><x-form.input name="hesabro_client" label="Client" :value="$hesabroClient" dir-ltr /><x-form.input name="hesabro_client_id" label="Client ID" :value="$hesabroClientId" dir-ltr /><x-form.input name="hesabro_client_secret" type="password" label="Client Secret" value="" dir-ltr help="برای حفظ مقدار فعلی، خالی بگذارید." /></div></div>
